css_custom_properties:
:root {
  /* ============================================
     CORDONNERIE MULTI-SERVICES SÀRL
     Design Tokens — Prêt à coller dans <style>
     Style : warm-artisan | Mood : chaleureux, solide, fiable
     ============================================ */

  /* --- Couleurs principales --- */
  --color-primary:         #C8102E; /* Rouge Victorinox — signature marque */
  --color-primary-dark:    #9B0C22; /* Rouge profond — hover, états actifs */
  --color-primary-light:   #E8334A; /* Rouge vif — icônes décoratives uniquement */
  --color-secondary:       #7A3B1E; /* Brun cuir — couleur artisan */
  --color-secondary-dark:  #5A2A12; /* Brun foncé — titres H2, backgrounds */
  --color-secondary-light: #A05830; /* Brun moyen — sous-titres */
  --color-accent:          #C19A3A; /* Or cuivre — ferrures, ornements */
  --color-accent-dark:     #8B6D20; /* Or sombre — texte accent si nécessaire */

  /* --- Surfaces et backgrounds --- */
  --color-surface:         #FFFFFF; /* Blanc pur — cartes, formulaires */
  --color-surface-alt:     #FAF7F2; /* Ivoire chaud — header, sections alternées */
  --color-surface-warm:    #F5EDE0; /* Ivoire cuir — trust bar, zones encadrées */
  --color-background:      #F2E8D9; /* Parchemin — fond général */

  /* --- Textes --- */
  --color-text-primary:    #1A1210; /* Brun quasi-noir — corps de texte principal */
  --color-text-secondary:  #4A3228; /* Brun moyen-foncé — descriptions */
  --color-text-muted:      #7A6055; /* Brun taupe — placeholders, métadonnées */
  --color-text-on-primary: #FFFFFF; /* Blanc sur rouge */
  --color-text-on-dark:    #F5EDE0; /* Ivoire sur fonds sombres */

  /* --- Bordures --- */
  --color-border:          #DDD0BF; /* Brun sable — bordures par défaut */
  --color-border-strong:   #C4B09A; /* Brun sable foncé — focus, séparateurs */

  /* --- États fonctionnels --- */
  --color-error:           #B91C1C;
  --color-success:         #15803D;
  --color-warning:         #B45309;

  /* ============================================ */
  /* --- Typographie --- */
  --font-heading:          'Playfair Display', Georgia, serif;
  --font-body:             'Source Sans 3', system-ui, -apple-system, sans-serif;

  /* Échelle typographique */
  --text-xs:               0.75rem;   /* 12px */
  --text-sm:               0.875rem;  /* 14px */
  --text-base:             1rem;      /* 16px */
  --text-lg:               1.125rem;  /* 18px */
  --text-xl:               1.25rem;   /* 20px */
  --text-2xl:              1.5rem;    /* 24px */
  --text-3xl:              1.875rem;  /* 30px */
  --text-4xl:              2.25rem;   /* 36px */
  --text-5xl:              3rem;      /* 48px */
  --text-6xl:              3.75rem;   /* 60px */

  /* Graisses */
  --font-light:            300;
  --font-regular:          400;
  --font-medium:           500;
  --font-semibold:         600;
  --font-bold:             700;
  --font-extrabold:        800;

  /* Hauteurs de ligne */
  --leading-tight:         1.2;
  --leading-snug:          1.35;
  --leading-normal:        1.5;
  --leading-relaxed:       1.625;
  --leading-loose:         1.8;

  /* Espacements lettres */
  --tracking-tighter:      -0.04em;
  --tracking-tight:        -0.02em;
  --tracking-normal:       0em;
  --tracking-wide:         0.04em;
  --tracking-wider:        0.08em;
  --tracking-widest:       0.16em;

  /* ============================================ */
  /* --- Espacements (grille 4px) --- */
  --space-1:               4px;
  --space-2:               8px;
  --space-3:               12px;
  --space-4:               16px;
  --space-5:               20px;
  --space-6:               24px;
  --space-8:               32px;
  --space-10:              40px;
  --space-12:              48px;
  --space-16:              64px;
  --space-20:              80px;
  --space-24:              96px;
  --space-32:              128px;

  /* ============================================ */
  /* --- Rayons de bordure --- */
  --radius-none:           0px;
  --radius-sm:             4px;
  --radius-md:             8px;
  --radius-lg:             12px;
  --radius-xl:             16px;
  --radius-2xl:            24px;
  --radius-3xl:            32px;
  --radius-full:           9999px;

  /* ============================================ */
  /* --- Ombres --- */
  --shadow-sm:             0 1px 3px rgba(26, 18, 16, 0.08), 0 1px 2px rgba(26, 18, 16, 0.06);
  --shadow-md:             0 4px 12px rgba(26, 18, 16, 0.10), 0 2px 6px rgba(26, 18, 16, 0.06);
  --shadow-lg:             0 8px 24px rgba(26, 18, 16, 0.12), 0 4px 10px rgba(26, 18, 16, 0.07);
  --shadow-xl:             0 16px 48px rgba(26, 18, 16, 0.15), 0 8px 20px rgba(26, 18, 16, 0.08);
  --shadow-primary:        0 4px 20px rgba(200, 16, 46, 0.28);
  --shadow-primary-hover:  0 8px 28px rgba(200, 16, 46, 0.36);
  --shadow-secondary:      0 4px 20px rgba(122, 59, 30, 0.25);
  --shadow-card-hover:     0 12px 32px rgba(26, 18, 16, 0.14), 0 4px 12px rgba(122, 59, 30, 0.08);
  --shadow-inset:          inset 0 2px 6px rgba(26, 18, 16, 0.08);

  /* ============================================ */
  /* --- Animations --- */
  --duration-instant:      80ms;
  --duration-fast:         150ms;
  --duration-normal:       250ms;
  --duration-slow:         400ms;
  --duration-slower:       600ms;

  --ease-default:          cubic-bezier(0.4, 0, 0.2, 1);
  --ease-in:               cubic-bezier(0.4, 0, 1, 1);
  --ease-out:              cubic-bezier(0, 0, 0.2, 1);
  --ease-spring:           cubic-bezier(0.34, 1.56, 0.64, 1);
  --ease-smooth:           cubic-bezier(0.25, 0.46, 0.45, 0.94);

  --transition-button:     background-color var(--duration-fast) var(--ease-default),
                           box-shadow var(--duration-fast) var(--ease-default),
                           transform var(--duration-fast) var(--ease-default);
  --transition-card:       box-shadow var(--duration-normal) var(--ease-default),
                           transform var(--duration-normal) var(--ease-default);
  --transition-link:       color var(--duration-fast) var(--ease-default);
  --transition-fade:       opacity var(--duration-normal) var(--ease-default);
  --transition-nav:        background-color var(--duration-normal) var(--ease-default),
                           box-shadow var(--duration-normal) var(--ease-default);

  /* ============================================ */
  /* --- Breakpoints (référence commentée) --- */
  /* --bp-xs:  480px  */
  /* --bp-sm:  640px  */
  /* --bp-md:  768px  */
  /* --bp-lg:  1024px */
  /* --bp-xl:  1280px */
  /* --bp-2xl: 1536px */

  /* ============================================ */
  /* --- Z-index --- */
  --z-base:                0;
  --z-raised:              10;
  --z-dropdown:            100;
  --z-sticky:              200;
  --z-overlay:             300;
  --z-modal:               400;
  --z-toast:               500;
  --z-tooltip:             600;

  /* ============================================ */
  /* --- Composants — Navigation --- */
  --nav-height:            72px;
  --nav-bg:                #FFFFFF;
  --nav-bg-scrolled:       #FAF7F2;
  --nav-border:            #DDD0BF;
  --nav-link-color:        #1A1210;
  --nav-link-hover:        #C8102E;
  --nav-shadow-scrolled:   0 2px 12px rgba(26, 18, 16, 0.10);

  /* --- Composants — Bouton primaire --- */
  --btn-primary-bg:        #C8102E;
  --btn-primary-color:     #FFFFFF;
  --btn-primary-hover-bg:  #9B0C22;
  --btn-primary-radius:    var(--radius-md);
  --btn-primary-padding:   12px 28px;
  --btn-primary-shadow:    var(--shadow-primary);

  /* --- Composants — Bouton secondaire --- */
  --btn-secondary-bg:      transparent;
  --btn-secondary-color:   #C8102E;
  --btn-secondary-border:  2px solid #C8102E;
  --btn-secondary-hover-bg: #C8102E;
  --btn-secondary-hover-color: #FFFFFF;

  /* --- Composants — Cartes de services --- */
  --card-bg:               #FFFFFF;
  --card-border:           1px solid #DDD0BF;
  --card-radius:           var(--radius-lg);
  --card-padding:          var(--space-6);
  --card-shadow:           var(--shadow-md);
  --card-hover-shadow:     var(--shadow-card-hover);
  --card-hover-transform:  translateY(-2px);

  /* --- Composants — Formulaire --- */
  --input-bg:              #FFFFFF;
  --input-border:          1.5px solid #DDD0BF;
  --input-border-focus:    #C8102E;
  --input-radius:          var(--radius-md);
  --input-padding:         12px 16px;
  --input-shadow-focus:    0 0 0 3px rgba(200, 16, 46, 0.15);

  /* --- Composants — Footer --- */
  --footer-bg:             #1A1210;
  --footer-text:           #C4B09A;
  --footer-title:          #F5EDE0;
  --footer-link:           #C4B09A;
  --footer-link-hover:     #C8102E;
  --footer-border-top:     3px solid #C8102E;

  /* --- Composants — Bannière cookie --- */
  --cookie-bg:             #1A1210;
  --cookie-text:           #C4B09A;
  --cookie-link:           #C8102E;
  --cookie-btn-bg:         #C8102E;
  --cookie-btn-color:      #FFFFFF;
}
